use gnosis_frf::prelude::*;
use regex::Regex;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex};
use std::time::Instant;

#[derive(Debug, Serialize, Deserialize, Default)]
struct KnotgraphEdge {
    #[serde(rename = "targetHash")]
    target_hash: String,
    r: u32,
    v: u32,
}

#[derive(Debug, Serialize, Deserialize, Default)]
struct KnotgraphBlock {
    #[serde(rename = "semanticValue")]
    semantic_value: String,
    edges: Vec<(String, KnotgraphEdge)>,
}

fn get_all_lean_files(dir: &Path) -> Vec<PathBuf> {
    let mut files = Vec::new();
    if let Ok(entries) = fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                files.extend(get_all_lean_files(&path));
            } else if path.extension().and_then(|s| s.to_str()) == Some("lean") {
                files.push(path);
            }
        }
    }
    files
}

fn clean_tactic(raw: &str) -> String {
    raw.replace("<;>", "").trim().to_string()
}

fn main() {
    let target_dir_str = std::env::args().nth(1).unwrap_or_else(|| {
        "../../../open-source/gnosis/lean".to_string()
    });
    let target_dir = Path::new(&target_dir_str);

    let base_files = get_all_lean_files(target_dir);
    if base_files.is_empty() {
        println!("No `.lean` files found in {}", target_dir.display());
        return;
    }
    println!("Found {} Lean files for gnosis-frf-accelerated Knot Extractor.", base_files.len());

    let tactic_regex = Regex::new(
        r"(simp \[.*?\]|simp|omega|linarith|nlinarith|ring|trivial|rfl|unfold [a-zA-Z0-9_]+|rw \[.*?\]|exact .*?|apply [a-zA-Z0-9_]+|have [a-zA-Z0-9_]+ .*? := .*?|intro [a-zA-Z0-9_]+|induction [a-zA-Z0-9_]+|split|refine .*?)"
    ).unwrap();

    let root_hash = "ROOT::Start".to_string();

    let knot_graph: Arc<Mutex<HashMap<String, KnotgraphBlock>>> = Arc::new(Mutex::new(HashMap::new()));
    knot_graph.lock().unwrap().insert(root_hash.clone(), KnotgraphBlock {
        semantic_value: "ROOT".to_string(),
        edges: Vec::new(),
    });

    let total_tactics = Arc::new(std::sync::atomic::AtomicUsize::new(0));

    let start_time = Instant::now();

    // Map each file into thread-local hash maps of transitions
    let mapped: Vec<Option<HashMap<String, HashMap<String, u32>>>> = base_files
        .par_iter()
        .map(|file| {
            let content = fs::read_to_string(file).ok()?;
            let mut thread_transitions: HashMap<String, HashMap<String, u32>> = HashMap::new();
            
            let blocks: Vec<&str> = content.split(":= by").collect();
            if blocks.len() > 1 {
                for block in &blocks[1..] {
                    // Extract until empty line or standard delimit
                    let stop_idx = block.find("\n\n").unwrap_or_else(|| {
                        block.find("end ").unwrap_or(block.len())
                    });
                    let sub_block = &block[..stop_idx];

                    let matches: Vec<String> = tactic_regex.find_iter(sub_block).map(|m| clean_tactic(m.as_str())).collect();
                    
                    let mut prev_hash = root_hash.clone();
                    for tactic in matches {
                        if tactic.is_empty() { continue; }
                        total_tactics.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                        
                        thread_transitions.entry(prev_hash.clone())
                            .or_default()
                            .entry(tactic.clone())
                            .and_modify(|count| *count += 5)
                            .or_insert(10); // Base weight is 10

                        prev_hash = tactic;
                    }
                }
            }
            Some(thread_transitions)
        })
        .collect();

    let local_graphs: Vec<HashMap<String, HashMap<String, u32>>> = mapped.into_iter().flatten().collect();

    // Fold over thread-local transitions and persist to root representation
    let mut final_graph = Arc::try_unwrap(knot_graph).unwrap().into_inner().unwrap();
    for thread_graph in local_graphs {
        for (source_hash, targets) in thread_graph {
            if !final_graph.contains_key(source_hash.as_str()) {
                final_graph.insert(source_hash.clone(), KnotgraphBlock {
                    semantic_value: source_hash.clone(),
                    edges: Vec::new(),
                });
            }

            for (target_hash, weight) in targets {
                if !final_graph.contains_key(target_hash.as_str()) {
                    final_graph.insert(target_hash.clone(), KnotgraphBlock {
                        semantic_value: target_hash.clone(),
                        edges: Vec::new(),
                    });
                }
                
                let source_block = final_graph.get_mut(&source_hash).unwrap();
                if let Some(edge) = source_block.edges.iter_mut().find(|(k, _)| *k == target_hash) {
                    edge.1.r += weight;
                } else {
                    source_block.edges.push((target_hash.clone(), KnotgraphEdge {
                        target_hash: target_hash.clone(),
                        r: weight,
                        v: 0,
                    }));
                }
            }
        }
    }

    let array_fmt: Vec<(String, KnotgraphBlock)> = final_graph.drain().collect();
    let root_pwd = std::env::current_dir().unwrap();
    let output_target = root_pwd.join("lean_prior.knot");
    
    fs::write(&output_target, serde_json::to_string_pretty(&array_fmt).unwrap()).unwrap();

    println!("\n⚡ gnosis-frf Codebase Extraction Complete. Time Elapsed: {:?}", start_time.elapsed());
    println!("Extracted {} total structured tactics.", total_tactics.load(std::sync::atomic::Ordering::Relaxed));
    println!("Topological collisions written to: {}", output_target.display());
    println!("Lean Toy-LLM Substrate size: {} active nodes mapped.", array_fmt.len());
}
